import { Button, GroupBox, ScrollView } from "std-widgets.slint";

export struct ScannerResultUiRow {
    row_kind: string,
    result_index: int,
    problem: string,
    mod_name: string,
    has_mod: bool,
}

export struct ScannerFileListUiRow {
    value: string,
    path: string,
}

component ScannerCheckOption inherits Rectangle {
    in property <string> category-id;
    in property <string> text;
    in property <string> help-text: "";
    in-out property <bool> checked: true;
    in property <bool> read-only: true;

    callback toggled(string, bool);

    min-height: root.help-text == "" ? 28px : 58px;

    HorizontalLayout {
        spacing: 8px;
        alignment: start;

        Rectangle {
            width: 15px;
            height: 15px;
            border-radius: 2px;
            border-width: 1px;
            border-color: root.checked ? #4da3ff : #9a9a9a;
            background: root.read-only ? #252525 : #303030;

            Text {
                text: root.checked ? "✓" : "";
                color: root.read-only ? #b8d9ff : #f3f3f3;
                font-size: 12px;
                horizontal-alignment: center;
                vertical-alignment: center;
            }
        }

        VerticalLayout {
            spacing: 2px;
            alignment: start;

            Text {
                text: root.text;
                color: root.read-only ? #d8d8d8 : #f3f3f3;
                font-size: 13px;
                vertical-alignment: center;
            }

            if root.help-text != "": Text {
                text: root.help-text;
                color: #8f8f8f;
                font-size: 10px;
                wrap: word-wrap;
            }
        }
    }

    TouchArea {
        clicked => {
            if (!root.read-only) {
                root.checked = !root.checked;
                root.toggled(root.category-id, root.checked);
            }
        }
    }
}

component ScannerProgressBar inherits Rectangle {
    in property <float> percent: 0;

    height: 12px;
    background: #303030;
    border-color: #484848;
    border-width: 1px;
    border-radius: 3px;

    Rectangle {
        x: 1px;
        y: 1px;
        height: parent.height - 2px;
        width: (parent.width - 2px) * root.percent / 100;
        background: #4da3ff;
        border-radius: 2px;
    }
}

component ScannerResultHeader inherits Rectangle {
    in property <bool> show-mod-column: false;

    height: 28px;
    background: #303030;
    border-color: #484848;
    border-width: 1px;
    border-radius: 3px;

    HorizontalLayout {
        padding-left: 8px;
        padding-right: 8px;
        spacing: 8px;
        alignment: start;

        Text {
            text: "Problem";
            width: root.show-mod-column ? 368px : 560px;
            color: #f3f3f3;
            font-size: 12px;
            font-weight: 700;
            vertical-alignment: center;
        }

        if root.show-mod-column: Text {
            text: "Mod";
            width: 176px;
            color: #f3f3f3;
            font-size: 12px;
            font-weight: 700;
            horizontal-alignment: right;
            vertical-alignment: center;
        }
    }
}

component ScannerResultRow inherits Rectangle {
    in property <ScannerResultUiRow> entry;
    in property <bool> show-mod-column: false;
    callback result-selected(int);

    property <bool> group-row: root.entry.row_kind == "group";

    min-height: root.group-row ? 30px : 32px;
    background: root.group-row ? #303030 : #262626;
    border-color: root.group-row ? #565656 : #383838;
    border-width: 1px;
    border-radius: 3px;

    HorizontalLayout {
        padding-left: root.group-row ? 8px : 18px;
        padding-right: 8px;
        spacing: 8px;
        alignment: start;

        Text {
            text: root.entry.problem;
            width: root.show-mod-column ? 358px : 550px;
            color: root.group-row ? #f3f3f3 : #d8d8d8;
            font-size: root.group-row ? 13px : 12px;
            font-weight: root.group-row ? 700 : 400;
            vertical-alignment: center;
            wrap: word-wrap;
        }

        if root.show-mod-column: Text {
            text: root.group-row || !root.entry.has_mod ? "" : root.entry.mod_name;
            width: 176px;
            color: #c8c8c8;
            font-size: 12px;
            horizontal-alignment: right;
            vertical-alignment: center;
            wrap: word-wrap;
        }
    }

    TouchArea {
        clicked => {
            if (!root.group-row) {
                root.result-selected(root.entry.result_index);
            }
        }
    }
}

component ScannerDetailValueRow inherits Rectangle {
    in property <string> label;
    in property <string> value;
    in property <length> label-width: 70px;

    min-height: 28px;

    HorizontalLayout {
        spacing: 6px;
        alignment: start;

        Text {
            text: root.label;
            width: root.label-width;
            color: #f3f3f3;
            font-size: 12px;
            font-weight: 600;
            horizontal-alignment: right;
            vertical-alignment: top;
        }

        Text {
            text: root.value;
            color: #d8d8d8;
            font-size: 12px;
            wrap: word-wrap;
        }
    }
}

component ScannerFileListPanel inherits Rectangle {
    in property <string> title;
    in property <string> description;
    in property <string> first-column: "Value";
    in property <string> second-column: "File";
    in property <[ScannerFileListUiRow]> rows;

    min-height: 128px;

    GroupBox {
        title: root.title;

        VerticalLayout {
            padding: 8px;
            spacing: 6px;
            alignment: start;

            if root.description != "": Text {
                text: root.description;
                color: #a8a8a8;
                font-size: 11px;
                wrap: word-wrap;
            }

            Rectangle {
                height: 24px;
                background: #303030;
                border-color: #484848;
                border-width: 1px;
                border-radius: 3px;

                HorizontalLayout {
                    padding-left: 5px;
                    padding-right: 5px;
                    spacing: 8px;
                    alignment: start;

                    Text {
                        text: root.first-column;
                        width: 72px;
                        color: #f3f3f3;
                        font-size: 11px;
                        font-weight: 700;
                        vertical-alignment: center;
                    }

                    Text {
                        text: root.second-column;
                        color: #f3f3f3;
                        font-size: 11px;
                        font-weight: 700;
                        vertical-alignment: center;
                    }
                }
            }

            ScrollView {
                min-height: 80px;

                VerticalLayout {
                    padding: 0px;
                    spacing: 4px;
                    alignment: start;

                    if root.rows.length == 0: Text {
                        text: "No file-list rows to display.";
                        color: #a8a8a8;
                        font-size: 11px;
                        wrap: word-wrap;
                    }

                    for entry in root.rows: Rectangle {
                        min-height: 24px;
                        background: #262626;
                        border-color: #383838;
                        border-width: 1px;
                        border-radius: 3px;

                        HorizontalLayout {
                            padding-left: 5px;
                            padding-right: 5px;
                            spacing: 8px;
                            alignment: start;

                            Text {
                                text: entry.value;
                                width: 72px;
                                color: #d8d8d8;
                                font-size: 11px;
                                vertical-alignment: center;
                                wrap: word-wrap;
                            }

                            Text {
                                text: entry.path;
                                color: #d8d8d8;
                                font-size: 11px;
                                vertical-alignment: center;
                                wrap: word-wrap;
                            }
                        }
                    }
                }
            }
        }
    }
}

component ScannerFeedbackBanner inherits Rectangle {
    in property <string> message;

    height: 32px;
    background: #263447;
    border-color: #5e8fc2;
    border-width: 1px;
    border-radius: 4px;

    Text {
        text: root.message;
        color: #d9ebff;
        font-size: 12px;
        x: 8px;
        y: 7px;
        wrap: word-wrap;
    }
}

